sql:
SELECT AVG(points_allowed_per_game) AS average_points_allowed
FROM defensive_statistics
WHERE team_id = 1 AND season_id = 0;

SELECT wins, losses, conference_wins, conference_losses
FROM team_season_records
WHERE team_id = 0 AND season_id = 1;

SELECT points_per_game, total_touchdowns
FROM offensive_statistics
WHERE season_id = 0;

